    <script>
        const API_URL = 'http://212.85.15.234:3001';
        const SECRET = 'antigravity2026secret';

        // SUBMIT NUEVA TAREA
        document.getElementById('tareaForm').addEventListener('submit', async (e) => {
            e.preventDefault();

            const proyecto = document.getElementById('proyecto').value;
            const descripcion = document.getElementById('descripcion').value;

            try {
                const response = await fetch(`${API_URL}/tarea`, {
                    method: 'POST',
                    headers: {
                        'Content-Type': 'application/json',
                        'X-Secret': SECRET
                    },
                    body: JSON.stringify({ proyecto, descripcion })
                });

                const data = await response.json();

                if (response.ok) {
                    alert(`Tarea creada: Job ${data.jobId}`);
                    document.getElementById('tareaForm').reset();
                    loadJobs();
                } else {
                    alert(`Error: ${data.error}`);
                }
            } catch (error) {
                alert(`Error de conexión: ${error.message}`);
            }
        });

        // CARGAR JOBS
        async function loadJobs() {
            try {
                const response = await fetch(`${API_URL}/jobs`, {
                    headers: { 'X-Secret': SECRET }
                });

                const data = await response.json();
                const jobsLog = document.getElementById('jobsLog');

                if (!data.jobs || data.jobs.length === 0) {
                    jobsLog.innerHTML = '<div class="empty-state">No hay jobs registrados aún</div>';
                    document.getElementById('activeJobsCount').textContent = '0';
                    return;
                }

                const activeCount = data.jobs.filter(j => j.status === 'EJECUTANDO' || j.status === 'EN COLA').length;
                document.getElementById('activeJobsCount').textContent = activeCount;

                jobsLog.innerHTML = data.jobs.map(job => {
                    const statusClass = {
                        'EN COLA': 'pending',
                        'EJECUTANDO': 'running',
                        'COMPLETADO': 'completed',
                        'ERROR': 'failed'
                    }[job.status] || 'pending';

                    return `
                        <div class="job-item">
                            <div class="job-header">
                                <span class="job-id">#${job.jobId}</span>
                                <span class="job-status ${statusClass}">${job.status}</span>
                            </div>
                            <div class="job-description">${job.descripcion}</div>
                            <div class="job-meta">
                                <span>Proyecto: ${job.proyecto}</span>
                                <span>Creado: ${new Date(job.createdAt).toLocaleString('es-AR')}</span>
                            </div>
                        </div>
                    `;
                }).join('');
            } catch (error) {
                console.error('Error cargando jobs:', error);
            }
        }

        // AUTO REFRESH JOBS cada 5 segundos
        function autoRefreshJobs() {
            setInterval(() => {
                loadJobs();
            }, 5000);
        }

        // INICIALIZAR
        loadJobs();
        autoRefreshJobs();
    </script>
